-- Migrate all 221 unique subcontratistas from transportistas.txt
-- This includes all provider companies with their contact information

DELETE FROM subcontratistas;

ON CONFLICT (rut) DO UPDATE SET 
  razon_social = EXCLUDED.razon_social,
  nombre_contacto = EXCLUDED.nombre_contacto,
  telefono = EXCLUDED.telefono,
  email = EXCLUDED.email,
  direccion = EXCLUDED.direccion,
  is_active = EXCLUDED.is_active,
  updated_at = NOW();

-- Verify the count
SELECT COUNT(*) as total_subcontratistas FROM subcontratistas;
